import{r as t,o as l,c as r,a as e,e as i,w as n,F as d,g as a,k as c}from"./app.437f405e.js";import{_ as m}from"./plugin-vue_export-helper.21dcd24c.js";const u={},h=a("\u{1F519} Back to "),g=e("strong",null,"Projects",-1),p=e("h1",{id:"sharingcloud-pr-bot",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#sharingcloud-pr-bot","aria-hidden":"true"},"#"),a(" SharingCloud PR Bot")],-1),b=c('<h2 id="summary" tabindex="-1"><a class="header-anchor" href="#summary" aria-hidden="true">#</a> Summary</h2><p>Experimental GitHub Bot to manage SharingCloud development workflows.<br> Uses <strong>PostgreSQL</strong> and <strong>Redis</strong>.</p><h3 id="why" tabindex="-1"><a class="header-anchor" href="#why" aria-hidden="true">#</a> Why ?</h3><p>GitHub is great and contains many useful features, but sometimes you need more. Today, you can use labels to have a quick view on the steps of your workflow, but you have to put them by hand, or write scripts to manipulate them.</p><p>One GitHub-hosted possibility is to use GitHub Actions as a workflow orchestrator (listening on pull request updates, added comments, or even check runs), but GitHub Actions <em>are</em> checks, so they need to boot at each GitHub event you want to support. They will also show on your Actions list, so your actual actions (as tests or builds) are not easily visible anymore.</p><p>Another problem with GA is that you need to duplicate your workflows for each of your repositories, even if you can use packages (as on GitHub Packages).</p><p>So here is another idea, why not use a centralized bot, which can react to webhook events to manage your workflows, can handle multiple repositories at once, maintaining state in a database and using per-repository configuration files ? Using the workflow events and GitHub API you can have almost real-time interactions.</p><p>Some bots like this already exists, like the Bors bot for the Rust programming language, but this bot will be more specifically designed for our own use-cases. Il will add some features:</p><ul><li>Use a command system through issue comments to drive the bot</li><li>Specify a regular expression to be matched for pull request titles</li><li>Specify manual QA status for a pull request (skipped, fail, pass, waiting)</li><li>Specify required reviewers for a particular pull request, and lock the merge if these reviews do not pass</li><li>Apply specific labels on pull requests depending on their current state</li><li>Maintain an automatically updated status comment with relevant details</li><li>And maintain a commit status to prevent or allow merge</li></ul><p>It will also be drivable via a command-line interface (for one-time actions as synchronizing state, or import/export), and if possible a terminal-like user interface (TUI, \xE0 la htop).</p><h3 id="features" tabindex="-1"><a class="header-anchor" href="#features" aria-hidden="true">#</a> Features</h3><ul><li>Manage PR lifecycle with local data stored in a PostgreSQL database</li><li>Reacts to GitHub Webhooks to update review status</li><li>Generate a summary comment (once per PR)</li><li>Validate PR titles depending on per-repository regexes</li><li>Reacts to comments: Set QA status (or skip), ping, lock/unlock, merge, etc.</li><li>Require mandatory reviewers</li><li>Merge support with merge rules depending on head and base branches (specific merge strategies)</li><li>Enable auto-merge</li><li>Actions that can be triggered from external sources, with simple token-based authentication</li><li>Give rights to external sources on specific repositories</li><li>Send GIFs!</li></ul><h3 id="step-labels" tabindex="-1"><a class="header-anchor" href="#step-labels" aria-hidden="true">#</a> Step labels</h3><p>Process can be followed with labels, which are auto applied depending on the current pull request state, in this order:</p><ul><li>PR is WIP? <strong>step/wip</strong></li><li>PR title is not valid? <strong>step/awaiting-changes</strong></li><li>Waiting for checks? <strong>step/awaiting-checks</strong></li><li>Checks failed? <strong>step/awaiting-changes</strong></li><li>Waiting for required reviews? <strong>step/awaiting-required-review</strong></li><li>Waiting for reviews? <strong>step/awaiting-reviews</strong></li><li>Waiting for QA? <strong>step/awaiting-qa</strong></li><li>QA failed? <strong>step/awaiting-changes</strong></li><li>PR is locked? <strong>step/locked</strong></li><li>All good? <strong>step/awaiting-merge</strong></li></ul><h3 id="available-message-commands" tabindex="-1"><a class="header-anchor" href="#available-message-commands" aria-hidden="true">#</a> Available message commands</h3><p>This README supposes the default bot handle: &#39;bot&#39;.</p><ul><li><code>bot noqa+</code>: <em>Skip QA validation</em></li><li><code>bot noqa-</code>: <em>Enable QA validation</em></li><li><code>bot qa+</code>: <em>Mark QA as passed</em></li><li><code>bot qa-</code>: <em>Mark QA as failed</em></li><li><code>bot qa?</code>: <em>Mark QA as waiting</em></li><li><code>bot nochecks+</code>: <em>Skip checks validation</em></li><li><code>bot nochecks-</code>: <em>Enable checks validation</em></li><li><code>bot automerge+</code>: <em>Enable auto-merge for this PR (once all checks pass)</em></li><li><code>bot automerge-</code>: <em>Disable auto-merge for this PR</em></li><li><code>bot lock+ &lt;reason?&gt;</code>: <em>Lock a pull-request (block merge)</em></li><li><code>bot lock- &lt;reason?&gt;</code>: <em>Unlock a pull-request (unblock merge)</em></li><li><code>bot req+ &lt;reviewers&gt;</code>: <em>Assign required reviewers (you can assign multiple reviewers)</em></li><li><code>bot req- &lt;reviewers&gt;</code>: <em>Unassign required reviewers (you can unassign multiple reviewers)</em></li><li><code>bot strategy+ &lt;strategy&gt;</code>: <em>Override merge strategy for this pull request</em></li><li><code>bot strategy-</code>: <em>Remove the overriden merge strategy for this pull request</em></li><li><code>bot merge &lt;merge|squash|rebase?&gt;</code>: <em>Try merging the pull request with optional strategy</em></li><li><code>bot ping</code>: <em>Ping me</em></li><li><code>bot gif &lt;search&gt;</code>: <em>Post a random GIF with a tag</em></li><li><code>bot is-admin</code>: <em>Check if you are admin</em></li><li><code>bot help</code>: <em>Show this comment</em></li></ul><h3 id="available-admin-message-commands" tabindex="-1"><a class="header-anchor" href="#available-admin-message-commands" aria-hidden="true">#</a> Available admin message commands</h3><p>If you have admin rights (you can set with <code>auth add-admin-rights &lt;username&gt;</code>), you have access to the following commands:</p><ul><li><code>bot admin-help</code>: <em>Show this comment</em></li><li><code>bot admin-enable</code>: <em>Enable me on a pull request with manual interaction</em></li><li><code>bot admin-disable</code>: <em>Disable me on a pull request with manual interaction</em></li><li><code>bot admin-set-default-needed-reviewers &lt;count&gt;</code>: <em>Set default needed reviewers count for this repository</em></li><li><code>bot admin-set-default-merge-strategy &lt;merge|squash|rebase&gt;</code>: <em>Set default merge strategy for this repository</em></li><li><code>bot admin-set-default-pr-title-regex &lt;regex?&gt;</code>: <em>Set default PR title validation regex for this repository</em></li><li><code>bot admin-set-default-automerge+</code>: <em>Set automerge enabled for this repository</em></li><li><code>bot admin-set-default-automerge-</code>: <em>Set automerge disabled for this repository</em></li><li><code>bot admin-set-default-qa-status+</code>: <em>Enable QA validation by default for this repository</em></li><li><code>bot admin-set-default-qa-status-</code>: <em>Disable QA validation by default for this repository</em></li><li><code>bot admin-set-default-checks-status+</code>: <em>Enable checks validation by default for this repository</em></li><li><code>bot admin-set-default-checks-status-</code>: <em>Disable checks validation by default for this repository</em></li><li><code>bot admin-set-needed-reviewers &lt;count&gt;</code>: <em>Set needed reviewers count for this PR</em></li><li><code>bot admin-reset-reviews</code>: <em>Reset and update reviews on pull request (maintenance-type command)</em></li><li><code>bot admin-reset-summary</code>: <em>Create a new summary message (maintenance-type command)</em></li><li><code>bot admin-sync</code>: <em>Update status comment if needed (maintenance-type command)</em></li></ul>',21);function f(w,y){const o=t("RouterLink"),s=t("ProjectCard");return l(),r(d,null,[e("p",null,[i(o,{to:"/projects/"},{default:n(()=>[h,g]),_:1})]),p,e("p",null,[i(s,{language:"Rust",date:"2021",status:"active",url:"https://github.com/sharingcloud/github-scbot"})]),b],64)}var q=m(u,[["render",f]]);export{q as default};
